            <a
              :href="item.link"
              class="centerSevice-mb-List-item"
              v-for="(item, index) in serverList"
              :key="index"
            >
              <h4 v-html="item.title"></h4>
              <div class="centerSevice-mb-List-item-text">
                <p v-for="(text, i) in item.textmb" :key="i">{{ text }}</p>
