  methods: {
    scrollToTopV2New() {
      window.scrollTo({ top: 0, behavior: "smooth" });
    },

    scrollToTopV2() {
      window.scrollTo({
        top: 0,
        behavior: "smooth",
      });
    },
    onMouseDown(e) {
      if (window.innerWidth > 992) {
        this.isDragging = true;
        this.hasDragged = false; // 鼠标按下时，重置拖动标志位
        this.$refs.UserShareBoxlist.style.cursor = "grabbing";
        this.startX = e.pageX;
        this.startScrollLeft = this.$refs.UserShareBoxlist.scrollLeft;
      }
    },
    onMouseMove(e) {
      if (window.innerWidth > 992) {
        if (this.isDragging) {
          this.hasDragged = true; // 只要鼠标移动了，就认为进行了拖动操作
          const x = e.pageX;
          const walk = x - this.startX;
          this.$refs.UserShareBoxlist.scrollLeft = this.startScrollLeft - walk;
        }
      }
    },

    onMouseUp() {
      if (window.innerWidth > 992) {
        this.isDragging = false;
        this.$refs.UserShareBoxlist.style.cursor = "grab";
      }
    },

    handleLinkClick(item, event) {
      if (this.hasDragged) {
        event.preventDefault(); // 如果进行了拖动操作，阻止 a 标签的默认点击行为
      } else {
        // 如果没有拖动，正常跳转
        window.open(item.href, "_blank");
      }
      this.hasDragged = false; // 处理完点击事件后，重置拖动标志位
    },
    // 获取背景颜色
    getColor(type) {
      return this.colorMap[type] || "white";
    },

    handleScroll() {
      const box = this.$refs.fourFeature; // 获取 box 元素
      const boxItemLeft = this.$refs.boxItemLeft; // 获取 boxitem-left 元素
      if (window.innerWidth < 992) {
        return;
      }
      if (!box || !boxItemLeft) return;

      // 获取相关元素的高度和位置
      const boxTop = box.offsetTop;
      const boxHeight = box.offsetHeight;
      const boxItemLeftHeight = boxItemLeft.offsetHeight;
      const scrollTop = window.scrollY || document.documentElement.scrollTop;

      // 动态调整 boxitem-left 的位置
      if (
        scrollTop > boxTop &&
        scrollTop < boxTop + boxHeight - boxItemLeftHeight
      ) {
        // 当滚动到 box 区域内，且 boxitem-left 的底边未到达 boxitem-right 的底边时
        boxItemLeft.style.position = "sticky";
        boxItemLeft.style.top = "160px";
      } else if (scrollTop >= boxTop + boxHeight - boxItemLeftHeight) {
        // 当 boxitem-left 的底边到达 boxitem-right 的底边时
        boxItemLeft.style.position = "relative";
        boxItemLeft.style.top = `${boxHeight - boxItemLeftHeight}px`;
      } else {
        // 滚动到 box 之前，恢复正常
        boxItemLeft.style.position = "sticky";
        boxItemLeft.style.top = "160px";
      }
    },

    async copyCurrentUrl() {
      try {
        const textArea = document.createElement("textarea");
        textArea.value = window.location.href;
        document.body.appendChild(textArea);
        textArea.select();
        document.execCommand("copy");
        document.body.removeChild(textArea);

        this.$message({
          showClose: true,
          message: "複製成功",
          type: "success",
        });
      } catch (error) {
        console.error("复制失败:", error);
      }
    },
  },
  beforeUnmount() {
    window.removeEventListener("scroll", this.handleScroll);
    if (this.$refs.UserShareBoxlist) {
      this.$refs.UserShareBoxlist.removeEventListener("mousedown", (e) => {
        e.preventDefault();
        this.onMouseDown(e);
      });
      document.removeEventListener("mousemove", this.onMouseMove);
      document.removeEventListener("mouseup", this.onMouseUp);
    }
  },
  mounted() {
    window.addEventListener("scroll", this.handleScroll);

    this.windowWidth = window.innerWidth;

    if (window.innerWidth < 768) {
      this.isMobile = true;
    } else {
      this.isMobile = false;
    }

    // 获取屏幕宽度
    window.addEventListener("resize", () => {
      if (window.innerWidth < 768) {
        this.isMobile = true;
      } else {
        this.isMobile = false;
      }
    });
    this.$nextTick(() => {
      if (this.$refs.UserShareBoxlist) {
        this.$refs.UserShareBoxlist.addEventListener("mousedown", (e) => {
          // 阻止 a 标签等元素的默认行为
          e.preventDefault();
          this.onMouseDown(e);
        });
        document.addEventListener("mousemove", this.onMouseMove);
        document.addEventListener("mouseup", this.onMouseUp);
      }
    });
  },
};
</script>



