            left: clamp(67.5px, 7.03vw, 135px);
            top: clamp(-46px, -2.4vw, -23px);
            height: clamp(16px, 1.67vw, 32px);
            width: 1px;
            background: #4570b6;
          }
        }
      }
      .centerIntroBox-bottom {
        max-width: clamp(531px, 55.31vw, 1062px);
        margin: clamp(14px, 1.46vw, 28px) auto 0;
        color: #6d6e71;
        text-align: center;
        font-family: "Noto Sans HK";
        font-size: clamp(10px, 1.04vw, 20px);
        font-style: normal;
        font-weight: 300;
        line-height: 1.75;
        letter-spacing: clamp(3px, 0.31vw, 6px);
      }
    }
  }

  // 矯視中心服務
  .centerSevice-service {
    margin-top: clamp(50px, 5.21vw, 100px);
    .centerSevice-service-title {
      text-align: center;
      color: #4570b6;
      font-family: "Noto Sans TC";
      font-size: clamp(15px, 1.56vw, 30px);
      font-style: normal;
      font-weight: 900;
      line-height: 1;
      letter-spacing: clamp(1.5px, 0.16vw, 3px);
    }
    .centerSevice-mb {
      display: none;
    }
  }
  .centerSevice {
    margin-top: clamp(55px, 5.73vw, 110px);
    .centerSeviceList {
      display: flex;
      flex-wrap: wrap;
      justify-content: center;
      gap: clamp(25px, 2.6vw, 50px);
      .pushable {
        position: relative;
        background: transparent;
        padding: 0px;
        border: none;
        cursor: pointer;
        outline-offset: clamp(2px, 0.21vw, 4px);
        outline-color: deeppink;
        transition: filter 250ms;
        -webkit-tap-highlight-color: rgba(0, 0, 0, 0);
        .shadow {
          position: absolute;
          top: 0;
          left: 0;
          height: 100%;
          width: 100%;
          background: #4570b6;
          border-radius: clamp(100px, 10.42vw, 200px);
          will-change: transform;
          transform: translateY(2px);
          transition: transform 600ms cubic-bezier(0.3, 0.7, 0.4, 1);
        }

        .edge {
          position: absolute;
          top: 0;
          left: 0;
          height: 100%;
          width: 100%;
          border-radius: clamp(100px, 10.42vw, 200px);
          background: #4570b6;
        }

        .front {
          display: block;
          position: relative;
          width: clamp(197.5px, 20.57vw, 395px);
          height: clamp(115px, 11.98vw, 230px);
          border-radius: clamp(100px, 10.42vw, 200px);
          background: #4570b6;
          border: 1px solid #4570b6;
          display: flex;
          flex-direction: column;
          align-items: center;
          justify-content: center;

          color: #fff;
          text-align: center;
          font-family: "ITC Avant Garde Gothic Pro";
          font-size: clamp(30px, 3.13vw, 60px);
          font-style: normal;
          font-weight: 700;
          line-height: 1.2;
          letter-spacing: clamp(1.8px, 0.19vw, 3.6px);
          transform: translateY(-4px);
          transition: all 600ms cubic-bezier(0.3, 0.7, 0.4, 1);
          overflow: hidden;

          .after-text {
            display: none;
          }
        }

        &:hover {
          filter: brightness(110%);
          .front {
            transform: translate(-6px, -6px);
            transition: transform 250ms cubic-bezier(0.3, 0.7, 0.4, 1.5);
            background: white;
            border: 1px solid #4570b6;
            color: #4570b6;
            text-align: center;
            font-family: "Noto Sans HK";
            font-size: clamp(10px, 1.04vw, 20px);
            font-style: normal;
            font-weight: 700;
            line-height: 1.75;
            letter-spacing: clamp(3px, 0.31vw, 6px);

            .front-text {
              display: none;
            }
            .after-text {
              display: block;
            }
          }

          .shadow {
            transform: translate(
              clamp(5.5px, 0.57vw, 11px),
              clamp(5.5px, 0.57vw, 11px)
            );
            transition: transform 250ms cubic-bezier(0.3, 0.7, 0.4, 1.5);
          }
        }

        &:active {
          .front {
            transform: translate(-2px, -2px);
            transition: transform 34ms;
          }

          .shadow {
            transform: translate(1px, 1px);
            transition: transform 34ms;
          }
        }

        &:focus:not(:focus-visible) {
          outline: none;
        }
      }
    }
    .centerSevice-btn {
      width: clamp(152px, 15.83vw, 304px);
      height: clamp(43px, 4.48vw, 86px);
      flex-shrink: 0;
      display: flex;
      justify-content: center;
      align-items: center;
      gap: clamp(7.5px, 0.78vw, 15px);
      background: #4570b6;
      border-radius: clamp(25px, 2.6vw, 50px);
      margin: clamp(85px, 8.85vw, 170px) auto 0;
      svg {
        width: clamp(11.5px, 1.2vw, 23px);
        height: clamp(11.5px, 1.2vw, 23px);
      }
      span {
        color: #fff;
        text-align: justify;
        font-family: "Noto Sans TC";
        font-size: clamp(18px, 1.88vw, 36px);
        font-style: normal;
        font-weight: 700;
        line-height: 1.75;
        letter-spacing: clamp(0.9px, 0.09vw, 1.8px);
      }
    }
  }

